import React from 'react';

const Navbar = () => {
  const navLinks = ['Services', 'About', 'Solutions', 'Explore Jobs', 'FAQ'];

  return (
    <nav className="bg-white/95 backdrop-blur-sm shadow-sm fixed w-full z-50 top-0 left-0">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-20">

          {/* Logo Section */}
          <div className="flex-shrink-0 flex items-center">
            <span className="text-3xl font-extrabold tracking-tighter text-[#1C1C1C]">
              HUDSON
            </span>
          </div>

          {/* Center Links Section */}
          <div className="hidden lg:flex items-center space-x-10">
            {navLinks.map((link) => (
              <a
                key={link}
                href="#"
                className="text-gray-700 hover:text-orange-600 font-medium text-[15px] transition-all"
              >
                {link}
              </a>
            ))}
          </div>

          {/* Right Buttons Section */}
          <div className="flex items-center space-x-4">
            <button className="text-orange-600 font-medium px-4 py-2 rounded-full border border-orange-200 hover:bg-orange-50">
              Sign In
            </button>
            <button className="btn-orange-gradient">
              Contact Us
            </button>
          </div>

        </div>
      </div>
    </nav>
  );
};

export default Navbar;
